#include <stdio.h>
#include <stdbool.h>

#define MAX_HOLES 10
#define MAX_PROCESS 5

typedef struct {
    int size;
    bool allocated;
} MemoryBlock;

int firstFit(MemoryBlock memory[], int n, int processSize) {
    for (int i = 0; i < n; i++) {
        if (!memory[i].allocated && memory[i].size >= processSize) {
            memory[i].allocated = true;
            return i;  // Return index of allocated block
        }
    }
    return -1;  // No suitable hole found
}

// Example: memory[] = {{30,false}, {20,false}, {15,false}, {40,false}}
// processSize = 18
// First Fit allocates to first block (30KB), returns index 0

#include <stdio.h>

int worstFit(int holes[], int n, int processSize) {
    int worstIdx = -1;
    int maxHole = -1;

    // Find the largest hole
    for (int i = 0; i < n; i++) {
        if (holes[i] >= processSize && holes[i] > maxHole) {
            maxHole = holes[i];
            worstIdx = i;
        }
    }

    if (worstIdx != -1) {
        // Allocate process, keep remaining as new hole
        holes[worstIdx] -= processSize;
        return worstIdx;
    }

    return -1;  // No hole large enough
}

/* Example:
holes = [10, 20, 15, 25]
processSize = 12

Worst Fit selects hole 25KB (index 3)
After allocation: holes = [10, 20, 15, 13]
